  const sumRows=list=>({budget:list.reduce((s,x)=>s+x.budget,0),forecast:list.reduce((s,x)=>s+x.forecast,0),actual:list.reduce((s,x)=>s+x.actual,0),ly:list.reduce((s,x)=>s+x.ly,0),lly:list.reduce((s,x)=>s+x.lly,0)});
