async function movements(ms,cats,y){
  let q='',pageNo=0,pageSize=250,running=0;
  const chronological=[...ms].sort((a,b)=>String(a.accounting_date).localeCompare(String(b.accounting_date))||(+a.id||0)-(+b.id||0));
  chronological.forEach(x=>{if(String(x.bank).toUpperCase()!=='CASH')running+=+x.amount||0;x.display_balance=running});
  const ordered=[...chronological].reverse(),currentBalance=chronological.length?chronological[chronological.length-1].display_balance:0;
  if(!sort.movements)sort.movements={k:'accounting_date',d:-1};
  const cols=[{k:'bank',l:'Banca',r:fullText},{k:'accounting_date',l:'Data movimento'},{k:'value_date',l:'Data valuta'},{k:'causale',l:'Causale',r:fullText},{k:'extended_description',l:'Descrizione estesa',r:(v,r)=>fullText(v||r.description)},{k:'movement',l:'Movimento',r:fullText},{k:'amount',l:'Importo',num:1,r:amountCents},{k:'display_balance',l:'Saldo progressivo',num:1,r:amountCents},{k:'category',l:'Voce app',r:(v,r)=>`<select data-cat="${r.id}" title="${esc(v||'Da classificare')}"><option>${esc(v||'Da classificare')}</option>${cats.filter(x=>+x.year===y).map(x=>`<option>${esc(x.name)}</option>`).join('')}</select>`},{k:'group',l:'Gruppo',r:fullText},{k:'note',l:'Note',r:v=>String(v||'').trim()?`<span title="${esc(v)}" aria-label="Nota presente">✓</span>`:''},{k:'id',l:'Gestione',r:(v,r)=>`<button data-edit-movement="${v}"${r.classification_mode==='manuale'?' class="manual-edit-button" title="Movimento modificato manualmente"':''}>Modifica</button>`}];
  const draw=()=>{const filtered=ordered.filter(x=>+x.year===y&&JSON.stringify(x).toLowerCase().includes(q)),pages=Math.max(1,Math.ceil(filtered.length/pageSize));if(pageNo>=pages)pageNo=pages-1;const rows=filtered.slice(pageNo*pageSize,(pageNo+1)*pageSize);$('#mov-table').innerHTML=table('movements',cols,rows);bindTable('movements',draw);enhanceSelects($('#mov-table'));document.querySelectorAll('[data-cat]').forEach(select=>select.onchange=async()=>{const x=ms.find(m=>m.id==select.dataset.cat),previous=x.category||'Da classificare',next=select.value;if(!await confirmChange('Conferma modifica voce',`Cambiare la voce da “${previous}” a “${next}”?`,'Modifica')){select.value=previous;select._smartSyncHandler?.();return}const cat=cats.find(c=>+c.year===y&&c.name===next);x.category=next;x.group=cat?.group||x.group;x.classification_mode='manuale';select.title=next;await put('movements',x);await render();toast('Voce aggiornata · report ricalcolati')});document.querySelectorAll('[data-edit-movement]').forEach(button=>button.onclick=()=>movementForm(ms.find(x=>x.id==button.dataset.editMovement),ms,cats,y));$('#mov-count').textContent=`${filtered.length.toLocaleString('it-IT')} movimenti`;$('#page-label').textContent=`Pagina ${pageNo+1} di ${pages}`;$('#prev').disabled=pageNo===0;$('#next').disabled=pageNo>=pages-1};
  $('#app').innerHTML=`<div class="card compact-page"><div class="section-head"><div><h2>Movimenti</h2><p class="muted">Inserisci o modifica movimenti, descrizioni, importi e note. CASH non concorre al saldo.</p></div><div class="movement-head-actions"><div class="current-balance"><small>Saldo attuale</small><strong class="${currentBalance<0?'bad':'good'}">${moneyCents(currentBalance)}</strong></div><button class="primary" id="new-movement">+ Nuovo movimento</button></div></div><div class="toolbar"><input id="search" placeholder="Cerca"><span id="mov-count"></span></div><div id="mov-table"></div><div class="toolbar"><button id="prev">← Precedente</button><span id="page-label"></span><button id="next">Successiva →</button></div></div>`;
  $('#new-movement').onclick=()=>movementForm(null,ms,cats,y);$('#search').oninput=frameDebounce(e=>{q=e.target.value.toLowerCase();pageNo=0;draw()});$('#prev').onclick=()=>{if(pageNo>0){pageNo--;draw()}};$('#next').onclick=()=>{pageNo++;draw()};draw();
}
async function categories(cats,y){
  await normalizeCategories(cats);cats=await all('categories');
  const rows=cats.filter(x=>+x.year===y),cols=[{k:'movement',l:'Movimento'},{k:'group',l:'Gruppo'},{k:'name',l:'Voce'},{k:'keywords',l:'Keyword esatta',r:v=>`<code class="keyword-exact" title="Gli spazi tra le barre fanno parte della keyword">|${esc(v)}|</code>`},{k:'name',l:'Gestione',r:(v,r)=>`<button data-edit-cat="${r.id}">Modifica</button>`}];
  const draw=()=>{$('#cat-table').innerHTML=table('categories',cols,rows);bindTable('categories',draw);document.querySelectorAll('[data-edit-cat]').forEach(button=>button.onclick=()=>categoryForm(cats.find(x=>x.id==button.dataset.editCat),y))};
  $('#app').innerHTML=`<div class="card compact-page"><div class="section-head"><div><h2>Voci dei prospetti · ${y}</h2><p class="muted">Ogni riga contiene una sola keyword. Gli spazi tra le barre | | sono parte della regola e vengono rispettati esattamente.</p></div><div class="plan-actions"><button class="primary" id="refresh-rules">↻ Aggiorna</button><button id="new-cat">+ Nuova voce</button></div></div><div id="cat-table"></div></div>`;$('#new-cat').onclick=()=>categoryForm(null,y);$('#refresh-rules').onclick=async()=>{if(!await confirmChange('Conferma aggiornamento','Rielaborare movimenti, Overview e tutti i report con le regole correnti?','Aggiorna'))return;const button=$('#refresh-rules');button.disabled=true;button.textContent='Aggiornamento…';try{const result=await recalculateAndRender(y);toast(`${result.processed.toLocaleString('it-IT')} movimenti automatici rielaborati · ${result.updated.toLocaleString('it-IT')} movimenti e ${result.plansUpdated.toLocaleString('it-IT')} prospetti aggiornati · modifiche manuali preservate`)}catch(error){button.disabled=false;button.textContent='↻ Aggiorna';toast(`Aggiornamento non riuscito: ${error.message}`)}};draw();
}
function categoryForm(c,y){
  modal(c?'Modifica voce':'Nuova voce',`<form id="category-form" class="form"><label>Movimento<select name="movement"><option>ENTRATE</option><option>USCITE</option></select></label><label>Gruppo<input name="group" value="${esc(c?.group||'')}"></label><label>Voce<input required name="name" value="${esc(c?.name||'')}"></label><label class="wide">Keyword esatta<input name="keywords" value="${esc(String(c?.keywords||'').split(';')[0])}" placeholder="Una sola parola o frase"><small>Gli eventuali spazi iniziali e finali vengono salvati e usati nella ricerca.</small></label><div class="category-form-actions wide">${c?'<button type="button" id="delete-category" class="danger">Elimina voce</button>':''}<button type="button" id="save-category" class="primary">Salva</button></div></form>`);
  const form=$('#category-form');if(c)form.movement.value=c.movement;
  const save=async()=>{if(!form.elements.namedItem('name').value.trim()){toast('Inserisci il nome della voce');return}const x=Object.fromEntries(new FormData(form)),keyword=x.keywords,existing=(await all('categories')).find(row=>+row.year===y&&row.id!==c?.id&&row.movement===x.movement&&keyword.trim()&&String(row.keywords||'').toLowerCase()===keyword.toLowerCase());if(existing){toast('Keyword esatta già presente in un’altra riga');return}if(!await confirmChange(c?'Conferma modifica voce':'Conferma nuova voce',c?`Applicare le modifiche alla voce ${c.name}?`:`Creare la nuova voce ${x.name}?`,'Conferma'))return;const button=$('#save-category');button.disabled=true;try{const oldDef=c?{movement:c.movement,group:c.group,name:c.name}:null,newDef={movement:x.movement,group:x.group,name:x.name};if(c&&(oldDef.movement!==newDef.movement||oldDef.group!==newDef.group||oldDef.name!==newDef.name)){const related=(await all('categories')).filter(row=>+row.year===y&&row.movement===oldDef.movement&&row.group===oldDef.group&&row.name===oldDef.name);for(const row of related)await put('categories',{...row,movement:newDef.movement,group:newDef.group,name:newDef.name,keywords:row.id===c.id?keyword:row.keywords});await renamePlanReferences(oldDef,newDef,y)}else{await put('categories',{...(c||{}),...x,year:y,keywords:keyword});await renamePlanReferences(newDef,newDef,y)}closeModal();const result=await recalculateAndRender(y);toast(`Voce salvata · ${result.updated.toLocaleString('it-IT')} movimenti e report ricalcolati`)}catch(error){button.disabled=false;toast(`Salvataggio non riuscito: ${error.message}`)}};$('#save-category').onclick=save;form.onsubmit=e=>{e.preventDefault();save()};if(c)$('#delete-category').onclick=()=>{modal('Elimina voce',`<p>Vuoi eliminare la regola <b>${esc(c.name)}</b> con keyword <code class="keyword-exact">|${esc(c.keywords||'')}|</code>?</p><p class="muted">Movimenti, Overview e report saranno ricalcolati automaticamente.</p><div class="toolbar"><button class="danger" id="confirm-category-delete">Elimina</button><button id="cancel-category-delete">Annulla</button></div>`);$('#cancel-category-delete').onclick=closeModal;$('#confirm-category-delete').onclick=async()=>{await del('categories',c.id);const remaining=(await all('categories')).some(row=>+row.year===y&&row.movement===c.movement&&row.group===c.group&&row.name===c.name);if(!remaining){const plans=await all('plans');for(const p of plans.filter(p=>+p.year===y&&p.scope!=='management'&&p.movement===c.movement&&p.group===c.group&&p.category===c.name))await del('plans',p.id)}closeModal();const result=await recalculateAndRender(y);toast(`Voce eliminata · ${result.updated.toLocaleString('it-IT')} movimenti e report ricalcolati`)}};
}
async function loansPage(loans,ms){let filter='APERTO',lastMovement=ms.map(x=>x.accounting_date).filter(Boolean).sort().pop(),cols=[{k:'description',l:'Finanziamento'},{k:'lender',l:'Finanziatore'},{k:'start',l:'Attivazione'},{k:'end',l:'Scadenza'},{k:'total',l:'Rate totali',num:1},{k:'paid',l:'Rate pagate',num:1},{k:'payment',l:'Rata',num:1,r:amount},{k:'status',l:'Stato'},{k:'id',l:'Gestione',r:v=>`<button data-loan="${v}">Modifica</button>`}];let calc=x=>{let a=new Date(x.start),b=new Date(x.end),cutoff=new Date(lastMovement||new Date()),months=(u,v)=>Math.max(0,(v.getFullYear()-u.getFullYear())*12+v.getMonth()-u.getMonth()+1);return{...x,total:months(a,b),paid:Math.min(months(a,cutoff),months(a,b))}},draw=()=>{let rows=loans.map(calc).filter(x=>filter==='TUTTI'||x.status===filter);$('#loan-table').innerHTML=table('loans',cols,rows);bindTable('loans',draw);document.querySelectorAll('[data-loan]').forEach(b=>b.onclick=()=>loanForm(loans.find(x=>x.id==b.dataset.loan)))};$('#app').innerHTML=`<div class="card"><div class="section-head"><div><h2>Finanziamenti</h2><p class="muted">Rate pagate calcolate fino all'ultimo movimento del ${lastMovement||'database'}.</p></div><button class="primary" id="new-loan">+ Nuovo</button></div><div class="toolbar"><label>Stato <select id="loan-filter"><option>TUTTI</option><option>APERTO</option><option>CHIUSO</option></select></label></div><div id="loan-table"></div></div>`;$('#loan-filter').value=filter;$('#loan-filter').onchange=e=>{filter=e.target.value;draw()};$('#new-loan').onclick=()=>loanForm();draw()}
function loanForm(x){modal(x?'Modifica finanziamento':'Nuovo finanziamento',`<form id="form" class="form"><label>Descrizione<input required name="description" value="${esc(x?.description||'')}"></label><label>Finanziatore<input name="lender" value="${esc(x?.lender||'')}"></label><label>Attivazione<div class="date-input"><input required type="date" name="start" value="${x?.start||''}"><button type="button" data-open-date="start" aria-label="Apri calendario attivazione">📅</button></div></label><label>Scadenza<div class="date-input"><input required type="date" name="end" value="${x?.end||''}"><button type="button" data-open-date="end" aria-label="Apri calendario scadenza">📅</button></div></label><label>Rata<input type="number" name="payment" value="${x?.payment||0}"></label><label>Stato<select name="status"><option>APERTO</option><option>CHIUSO</option></select></label><button class="primary wide">Salva</button></form>`);let f=$('#form');if(x)f.status.value=x.status;bindDatePickers(f);f.onsubmit=async e=>{e.preventDefault();if(!await confirmChange(x?'Conferma modifica finanziamento':'Conferma nuovo finanziamento',x?'Applicare le modifiche al finanziamento?':'Creare il nuovo finanziamento?','Conferma'))return;let v=Object.fromEntries(new FormData(f));v.payment=+v.payment;await put('loans',{...(x||{}),...v});closeModal();render();toast('Finanziamento salvato')}}
function normalizedText(value){return String(value??'').normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/\s+/g,' ').trim().toUpperCase()}function movementKeys(x){const base=[x.accounting_date||'',x.value_date||'',Math.round((+x.amount||0)*100)].join('|'),causale=normalizedText(x.causale),description=normalizedText(x.extended_description||x.description),label=causale||normalizedText(x.description);return[`STRICT|${base}|${causale}|${description}`,`LABEL|${base}|${label}`]}function fingerprint(x){return movementKeys(x)[0]}
function excelDate(v){if(v instanceof Date&&!isNaN(v))return`${v.getFullYear()}-${String(v.getMonth()+1).padStart(2,'0')}-${String(v.getDate()).padStart(2,'0')}`;if(typeof v==='number'){let d=XLSX.SSF.parse_date_code(v);return d?`${d.y}-${String(d.m).padStart(2,'0')}-${String(d.d).padStart(2,'0')}`:''}let s=String(v||'').trim(),m=s.match(/(\d{1,2})[\/.\-](\d{1,2})[\/.\-](\d{4})/);return m?`${m[3]}-${m[2].padStart(2,'0')}-${m[1].padStart(2,'0')}`:s.slice(0,10)}function pick(o,names){const entries=Object.entries(o),wanted=names.map(normalizedText),exact=entries.find(([key])=>wanted.includes(normalizedText(key))),partial=entries.find(([key])=>wanted.some(name=>normalizedText(key).includes(name)));return(exact||partial)?.[1]??''}
async function importExcel(file){
  if(!window.XLSX)throw Error('Libreria Excel non disponibile: controlla la connessione');
  const wb=XLSX.read(await file.arrayBuffer(),{type:'array',cellDates:true});let sheet,headerIndex=-1;for(const name of wb.SheetNames){const candidate=wb.Sheets[name],matrix=XLSX.utils.sheet_to_json(candidate,{header:1,defval:''}),index=matrix.findIndex(row=>{const headers=row.map(normalizedText);return headers.includes('DATA CONTABILE')||headers.includes('DATA MOVIMENTO')||headers.includes('DATA OPERAZIONE')});if(index>=0){sheet=candidate;headerIndex=index;break}}if(!sheet)throw Error('Intestazione dei movimenti non trovata nel file');
  const rows=XLSX.utils.sheet_to_json(sheet,{range:headerIndex,defval:''}),old=await all('movements'),index=new Map,used=new Set,cats=await all('categories'),affectedYears=new Set;old.forEach((movement,i)=>movementKeys(movement).forEach(key=>{if(!index.has(key))index.set(key,[]);index.get(key).push(i)}));const consume=keys=>{for(const key of keys){const candidates=index.get(key)||[];while(candidates.length&&used.has(candidates[0]))candidates.shift();if(candidates.length){used.add(candidates.shift());return true}}return false};let added=0,dups=0,skipped=0;
  for(const row of rows){
    const date=excelDate(pick(row,['data movimento','data contabile','data operazione'])),valueDate=excelDate(pick(row,['data valuta','valuta']))||date,shortDescription=String(pick(row,['descrizione','causale','tipo operazione'])),causale=String(pick(row,['causale','tipo operazione'])||shortDescription),desc=String(pick(row,['descrizione estesa','descrizione completa'])||shortDescription||causale),credit=+pick(row,['accrediti','accredito','entrate','avere'])||0,debit=+pick(row,['addebiti','addebito','uscite','dare'])||0;let amount=+(pick(row,['importo','amount'])||0);if(!amount)amount=credit-Math.abs(debit);if(!/^\d{4}-\d{2}-\d{2}$/.test(date)||!Number.isFinite(amount)||(!amount&&!credit&&!debit)){skipped++;continue}
    const x={bank:'ISP',accounting_date:date,value_date:valueDate,causale,description:desc,extended_description:desc,combined:`${causale} ${desc}`.trim(),amount,credit:amount>0?amount:credit,debit:amount<0?Math.abs(amount):debit,currency:String(pick(row,['divisa','currency'])||'EUR'),balance:+pick(row,['saldo progressivo','saldo'])||0,year:+date.slice(0,4),month:+date.slice(5,7),movement:amount>=0?'ENTRATE':'USCITE',note:String(pick(row,['note'])),excluded:false,classification_mode:'regola'};
    x.category=classifyMovement(x,cats);const rule=cats.find(c=>+c.year===x.year&&c.name===x.category&&c.movement===x.movement);x.group=rule?.group||'';
    if(consume(movementKeys(x))){dups++;continue}x.fingerprint=fingerprint(x);await put('movements',x);affectedYears.add(x.year);added++;
  }
  let currentCats=await all('categories'),reclassified=0;
  for(const year of affectedYears){await cloneCategories(currentCats,year);currentCats=await all('categories');const result=await reclassifyYear(year,currentCats);reclassified+=result.processed}
  return{added,dups,skipped,reclassified,affectedYears:[...affectedYears]};
}
async function backupPage(){let counts=Object.fromEntries(await Promise.all(stores.slice(0,4).map(async s=>[s,(await all(s)).length])));$('#app').innerHTML=`<div class="grid"><div class="card"><h2>Importa nuovi movimenti</h2><p class="muted">File .xlsx/.xls. Le righe già presenti vengono riconosciute e ignorate.</p><input type="file" id="excel" accept=".xlsx,.xls,.xlsb"><button class="primary" id="do-import">Importa Excel</button><p id="result"></p></div><div class="card"><h2>Backup privato</h2><p class="muted">Scarica il database completo e conservalo nel tuo Google Drive. Per ripristinarlo, seleziona il file JSON.</p><div class="toolbar"><button class="primary" id="export">Scarica backup</button><input type="file" id="restore" accept=".json"></div></div><div class="card span2"><h2>Dati salvati in questo browser</h2><p>Movimenti: <b>${counts.movements}</b> · Voci: <b>${counts.categories}</b> · Piani: <b>${counts.plans}</b> · Finanziamenti: <b>${counts.loans}</b></p><p class="muted">GitHub non riceve mai questi dati. Se cancelli i dati del browser senza backup, non possono essere recuperati.</p></div></div>`;$('#do-import').onclick=async()=>{let f=$('#excel').files[0];if(!f)return toast('Seleziona un file Excel');if(!await confirmChange('Conferma importazione',`Importare i nuovi movimenti dal file ${f.name} e aggiornare tutti i report?`,'Importa'))return;const button=$('#do-import');button.disabled=true;$('#result').textContent='Confronto con la tabella Movimenti…';try{let r=await importExcel(f);await refreshYears();await render();if($('#result'))$('#result').innerHTML=`<b>${r.added}</b> nuove righe categorizzate · <b>${r.dups}</b> già presenti · report aggiornati`;toast(`${r.added} nuovi movimenti categorizzati · Overview e report aggiornati`)}catch(e){button.disabled=false;$('#result').textContent=e.message}};$('#export').onclick=exportBackup;$('#restore').onchange=async e=>{const file=e.target.files[0];if(!file)return;if(await confirmChange('Conferma ripristino','Sostituire i dati correnti con quelli del backup selezionato?','Ripristina'))restoreBackup(file);else e.target.value=''}}
async function logicPage(ms,cats,plans,y){const yearMovements=ms.filter(x=>+x.year===y&&!x.is_opening_balance),yearRules=cats.filter(x=>+x.year===y),manual=yearMovements.filter(x=>x.classification_mode==='manuale').length,last=[...yearMovements].filter(x=>x.accounting_date).sort((a,b)=>String(a.accounting_date).localeCompare(String(b.accounting_date))).pop(),cash=overviewIncomeCash(ms,y),sections=[
  {id:'flusso',tag:'ORDINARIA',title:'Flusso e aggiornamento dei dati',summary:'Dal file Excel ai report, senza duplicazioni.',body:`<ol><li>L'importazione confronta più chiavi identificative con MOVIMENTI e inserisce soltanto le righe nuove.</li><li>Le nuove righe ricevono banca ISP quando la banca è vuota.</li><li>Dopo importazione, modifica o riclassificazione vengono ricalcolati Overview e report.</li><li>I dati restano nel database del browser; GitHub pubblica soltanto l'app.</li></ol>`},
  {id:'categorie',tag:'ORDINARIA',title:'Associazione Regole e Categorie',summary:'Causale e descrizione estesa determinano la Voce.',body:`<ol><li>La ricerca usa insieme <b>Causale</b> e <b>Descrizione estesa</b>.</li><li>Le keyword conservano gli spazi significativi; tra più corrispondenze prevale la keyword specifica più lunga.</li><li>La regola è applicata soltanto al Movimento coerente: ENTRATE oppure USCITE.</li><li>Se nessuna regola coincide, vengono usate ENTRATE VARIE o USCITE VARIE.</li><li>Le voci modificate manualmente sono protette dagli aggiornamenti automatici e il pulsante Modifica diventa giallo.</li></ol>`},
  {id:'cash',tag:'STRAORDINARIA',title:'Gestione CASH',summary:'CASH è escluso dal saldo bancario e rettificato nei report.',body:`<div class="logic-formula"><span>Principali entrate</span><b>${money(cash.cashPositive)} − ${money(cash.withdrawalsPositive)} = ${money(cash.net)}</b><small>|Totale banca CASH| − |PRELEVAMENTI negativi|</small></div><ul><li>La banca CASH non concorre al Saldo disponibile né al Saldo progressivo bancario.</li><li>In Principali entrate, il totale netto confluisce in ENTRATE VARIE.</li><li>Entrambi gli elementi della formula sono esposti come valori positivi prima della sottrazione.</li><li>Nel dettaglio ACTUAL, la componente CASH resta esplicitata separatamente.</li></ul>`},
  {id:'actual',tag:'ORDINARIA',title:'Actual vs FRCST',summary:'ACTUAL nasce esclusivamente dalle righe MOVIMENTI.',body:`<ol><li>Ogni voce usa la chiave completa <b>Movimento · Gruppo · Voce</b>.</li><li>Anno e mesi selezionati filtrano direttamente MOVIMENTI; apertura ed esclusioni non entrano nel calcolo.</li><li>LY e LLY applicano la stessa selezione mesi ai due anni precedenti.</li><li>Budget e Forecast sono proporzionati ai mesi selezionati.</li><li>Δ Actual vs FRCST = Forecast − Actual.</li></ol>`},
  {id:'budget',tag:'ORDINARIA',title:'Budget e Forecast',summary:'Pianificazione modificabile con righe di dettaglio.',body:`<ul><li>Una riga principale identifica Movimento, Gruppo e Voce.</li><li>Budget e Forecast sono la somma delle righe di dettaglio.</li><li>Creazione, modifica ed eliminazione richiedono conferma.</li><li>Per ogni voce restano visibili ACTUAL, LY e LLY.</li></ul>`},
  {id:'anni',tag:'STRAORDINARIA',title:'Anni, continuità e storicità',summary:'Gli anni chiusi restano separati; dal 2027 si replica Y−1.',body:`<ul><li>Regole, categorie e pianificazione sono gestite per anno.</li><li>Dal 2027, se l'anno non esiste, le voci partono dalla struttura dell'anno precedente.</li><li>Gli anni storici non vengono modificati dalla duplicazione automatica.</li><li>Le modifiche manuali ai movimenti restano sempre prioritarie.</li></ul>`},
  {id:'finanziamenti',tag:'ORDINARIA',title:'Finanziamenti',summary:'Rate e stato derivano da date e ultimo movimento.',body:`<ul><li>Una rata equivale a un mese.</li><li>Le rate totali derivano da attivazione e scadenza.</li><li>Le rate pagate sono calcolate fino alla data dell'ultimo movimento disponibile.</li><li>Il filtro iniziale mostra i finanziamenti APERTI.</li></ul>`},
  {id:'formati',tag:'TRASVERSALE',title:'Segni, colori e conferme',summary:'La lettura economica determina il colore.',body:`<ul><li>Gli importi negativi usano il segno meno, mai le parentesi.</li><li>Rosso indica effetto sfavorevole; verde effetto favorevole o risparmio.</li><li>Gli importi MOVIMENTI mantengono i centesimi; i prospetti mostrano valori interi.</li><li>Ogni modifica persistente richiede conferma prima del salvataggio.</li></ul>`}
];$('#app').innerHTML=`<div class="logic-page"><div class="card logic-hero"><div><small>MAPPA FUNZIONALE · ${y}</small><h2>Logiche di Home Finance</h2><p>Regole operative aggiornate in base al comportamento effettivo dell'app.</p></div><div class="logic-live"><span><b>${yearMovements.length.toLocaleString('it-IT')}</b> movimenti</span><span><b>${yearRules.length.toLocaleString('it-IT')}</b> regole</span><span><b>${manual.toLocaleString('it-IT')}</b> manuali</span><span><b>${esc(last?.accounting_date||'–')}</b> ultimo dato</span></div></div><div class="card logic-flow"><button data-logic-target="flusso">Importazione</button><i>→</i><button data-logic-target="categorie">Classificazione</button><i>→</i><button data-logic-target="actual">Calcoli</button><i>→</i><button data-logic-target="cash">Eccezioni</button><i>→</i><button data-logic-target="budget">Report</button></div><div class="card logic-tools"><input id="logic-search" type="search" placeholder="Cerca una logica…"><button id="logic-expand">Espandi tutte</button><button id="logic-collapse">Comprimi tutte</button></div><div class="logic-sections">${sections.map((section,index)=>`<details class="card logic-item" id="logic-${section.id}" ${index===0?'open':''}><summary><div><span>${section.tag}</span><h3>${section.title}</h3><p>${section.summary}</p></div><b>＋</b></summary><div class="logic-body">${section.body}</div></details>`).join('')}</div></div>`;const items=[...document.querySelectorAll('.logic-item')];$('#logic-search').oninput=e=>{const q=normalizedText(e.target.value);items.forEach(item=>{const match=!q||normalizedText(item.textContent).includes(q);item.hidden=!match;if(q&&match)item.open=true})};$('#logic-expand').onclick=()=>items.filter(x=>!x.hidden).forEach(x=>x.open=true);$('#logic-collapse').onclick=()=>items.forEach(x=>x.open=false);document.querySelectorAll('[data-logic-target]').forEach(button=>button.onclick=()=>{const item=$(`#logic-${button.dataset.logicTarget}`);item.hidden=false;item.open=true;item.scrollIntoView({behavior:'smooth',block:'start'})})}
async function exportBackup(){let data={format:'casa-finance-backup',version:1,createdAt:new Date().toISOString(),data:{}};for(let s of stores)data.data[s]=await all(s);let a=document.createElement('a');a.href=URL.createObjectURL(new Blob([JSON.stringify(data)],{type:'application/json'}));a.download=`casa-finance-backup-${new Date().toISOString().slice(0,10)}.json`;a.click();URL.revokeObjectURL(a.href)}async function restoreBackup(file){try{let x=JSON.parse(await file.text());if(x.format==='casa-finance-plan-update'){const existing=await all('plans');for(const p of existing)if(+p.year>=2017&&+p.year<=2025)await del('plans',p.id);for(const source of x.data?.plans||[]){const p={...source};delete p.id;await put('plans',p)}toast(`${x.data?.plans?.length||0} piani storici aggiornati`)}else{if(x.format!=='casa-finance-backup')throw Error('Formato backup non valido');for(let s of stores){await clear(s);for(let v of x.data[s]||[])await put(s,v)}await ensureRuleMigration();await ensureSearchFieldsMigration();await ensureVarieFigliMigration();await normalizeBlankBanks();toast('Backup ripristinato · Overview e report aggiornati')}await ensureHistoricalReportMigration();await ensureMovementActualMigration();await refreshYears();render()}catch(e){toast(e.message)}}
async function cloneCategories(cats,y){if(y<2027||cats.some(x=>+x.year===y))return;let prev=cats.filter(x=>+x.year===y-1);for(let c of prev){let n={...c,year:y};delete n.id;await put('categories',n)}}async function refreshYears(){let ms=await all('movements'),ys=years(ms),sel=$('#year'),old=+sel.value||ys[0];sel.innerHTML=ys.map(y=>`<option>${y}</option>`).join('');sel.value=ys.includes(old)?old:ys[0]}
async function render(){closeSmartSelects();const version=++renderVersion;renderNav();const y=+$('#year').value,requestedPage=page,label=requestedPage===logicNav[0]?logicNav[1]:Object.values(navs).flat().find(x=>x[0]===requestedPage)?.[1];$('#title').textContent=label;$('#crumb').textContent=label;$('#app').innerHTML='<div class="card">Caricamento…</div>';let[ms,cats,plans,loans]=await Promise.all([all('movements'),all('categories'),all('plans'),all('loans')]);if(y>=2027&&!cats.some(x=>+x.year===y)){await cloneCategories(cats,y);cats=await all('categories')}if(version!==renderVersion)return;if(requestedPage==='saldo')await saldo(ms,cats,plans,y);else if(requestedPage==='planning')await planning(ms,cats,plans,y);else if(requestedPage==='budget')await budgetPage(ms,cats,plans,y);else if(requestedPage==='movimenti')await movements(ms,cats,y);else if(requestedPage==='categorie')await categories(cats,y);else if(requestedPage==='finanziamenti')await loansPage(loans,ms);else if(requestedPage==='logiche')await logicPage(ms,cats,plans,y);else await backupPage();if(version===renderVersion)enhanceSelects()}
